// 1. Extraer los datos del body (donde llega el POST del CRM)
const body = $input.item.json.body || {};

// 2. Obtener y formatear la fecha
const fechaOriginal = body.fecha_cita || $input.item.json.fecha_cita;
const fecha = new Date(fechaOriginal);

const opciones = { 
  weekday: 'long', 
  year: 'numeric', 
  month: 'long', 
  day: 'numeric', 
  hour: '2-digit', 
  minute: '2-digit',
  hour12: true 
};

// 3. Retornar un objeto plano con todos los campos en la raíz
// Esto asegura que el nodo 'Enviar Email' vea 'cliente_email', 'servicio', etc.
return {
  json: {
    ...body,
    fecha_legible: isNaN(fecha.getTime()) ? 'Fecha pendiente de confirmación' : fecha.toLocaleDateString('es-CO', opciones)
  }
};
